dark.customCSS:
/* 1. CORE AESTHETIC: Blueprint Grid & Dark Background */
body {
    background-color: #020408 !important; /* Restored deep obsidian base */
    background-image: 
        linear-gradient(rgba(26, 177, 255, 0.04) 1px, transparent 1px), 
        linear-gradient(90deg, rgba(26, 177, 255, 0.04) 1px, transparent 1px) !important;
    background-size: 24px 24px !important;
    background-position: center top !important;
    font-family: 'JetBrains Mono', 'Monaco', monospace !important;
}

/* 2. SOFT BORDERS: Clean technical lines */
* {
    border-color: rgba(26, 177, 255, 0.15) !important;
}

/* 3. INPUTS & TEXT AREAS: Darkened with indigo tint */
input, textarea, .tiptap, .prose-editor, .bg-gray-50, .dark\:bg-gray-850 {
    background-color: rgba(10, 21, 32, 0.95) !important; /* Darker, more solid indigo */
    border: 1px solid rgba(26, 177, 255, 0.3) !important;
    color: #e6f7ff !important;
    border-radius: 8px !important;
}

/* 4. CHAT HISTORY: Clean, minimally intrusive separators */
.chat-user, .chat-assistant {
    background: transparent !important;
    border: none !important;
}

.user-message, .assistant-message {
    border-bottom: 1px solid rgba(26, 177, 255, 0.08) !important;
}

/* 5. SIDEBAR: Darker, blurred navigation */
#sidebar, .sidebar-container {
    background-color: rgba(2, 4, 8, 0.9) !important; /* Darkened sidebar */
    backdrop-filter: blur(12px);
    border-right: 1px solid rgba(26, 177, 255, 0.1) !important;
}

#sidebar-chat-item.bg-gray-100\/10, 
#sidebar-chat-item.bg-gray-850 {
    background-color: rgba(26, 177, 255, 0.12) !important;
    border-left: 2px solid #1ab1ff !important;
}

/* 6. MARKDOWN & CODE: Clean legibility */
.prose {
    color: #b3e6ff !important;
}

.prose pre {
    background-color: rgba(2, 4, 8, 0.95) !important;
    border: 1px solid rgba(26, 177, 255, 0.2) !important;
    border-radius: 8px !important;
}

.prose code:not(pre code) {
    background-color: rgba(26, 177, 255, 0.12) !important;
    color: #1ab1ff !important;
}

/* 7. ACCENT BUTTONS: Reverted to your bold high-contrast style */
button.bg-blue-500, button.bg-blue-600, .bg-blue-600 {
    background-color: #1ab1ff !important;
    border: 1px solid #e6f7ff !important;
    color: #020408 !important;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: bold;
    border-radius: 6px !important;
}

/* 8. SCROLLBAR & SELECTION */
::-webkit-scrollbar-thumb {
    background: rgba(26, 177, 255, 0.35) !important;
}

::selection {
    background: rgba(26, 177, 255, 0.3) !important;
    color: #ffffff !important;
}

/* Keep shadows hidden for that flat CAD drawing feel */
* {
    box-shadow: none !important;
}

